"""
mkt-christ | malachi | ch1–4 (ch3:1 and ch4:5 already exist)
run: python3 scripts/zc-christ-malachi-1-4.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MALACHI = {
  "1": {
    "1": "<p>A theme: The <em>massa'</em> (burden/oracle) addressed 'to Israel through Malachi' frames the entire book as YHWH's final covenantal charge before the long silence between Testaments. Christ is the one who ends that silence: 'Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son' (Heb 1:1-2). Malachi's oracle is the last word; the incarnation is the Word made flesh.</p>",
    "2": "<p>A revelation of God: 'I have loved you, says YHWH. But you say, How have you loved us?' The divine love questioned by the people is the context in which Rom 5:8 speaks: 'God shows his love for us in that while we were still sinners, Christ died for us.' The interrogated love of YHWH becomes the demonstrated love of the cross. 1 John 4:10: 'This is love, not that we loved God but that he loved us and sent his Son to be the propitiation for our sins.'</p>",
    "3": "<p>A revelation of God: 'I have loved Jacob but Esau I have hated.' The sovereign distinction between Jacob and Esau becomes the proof-text of divine election in Rom 9:13. Paul does not explain the mystery away but insists that God's purpose of election stands 'not because of works but because of him who calls' (Rom 9:11). The electing love that chose Jacob anticipates the electing grace that chose the church 'before the foundation of the world' (Eph 1:4).</p>",
    "4": "<p>A theme: The futility of Edom's rebuilding — 'they will build but I will tear down' — illustrates the divine sovereignty over proud human projects. Jesus applies a similar principle in warning against building on sand (Matt 7:26-27); the kingdom built by YHWH (Ps 127:1) is the only lasting structure. The city that endures is the one 'whose architect and builder is God' (Heb 11:10).</p>",
    "5": "<p>A direct: 'Your own eyes will see this, and you will say: Great is YHWH beyond the border of Israel!' The expansion of divine recognition beyond Israel's borders is the missionary horizon fulfilled in the gospel's advance. Acts 1:8 ('to the ends of the earth'), Rev 7:9 ('every nation, tribe, people, and language'), and Rom 10:18 ('their voice has gone out to all the earth') are the NT realization of what Malachi anticipates: YHWH's greatness acknowledged by all peoples through the gospel of Christ.</p>",
    "6": "<p>A theme: 'A son honors his father, and a servant his master. If then I am a Father, where is my honor? And if I am a Master, where is my fear?' The double relation — Father-Son and Master-Servant — is the framework within which Jesus operates perfectly. 'The Son can do nothing of his own accord, but only what he sees the Father doing' (John 5:19); 'I always do the things that are pleasing to him' (John 8:29). Jesus is the perfect Son who renders the perfect honor the Father is owed.</p>",
    "7": "<p>A theme: 'You offer polluted food on my altar. But you say, How have we polluted you?' The inadequacy of impure worship — offering what costs nothing, which is no offering at all — is the foil for Jesus's teaching on true worship: 'God is spirit, and those who worship him must worship in spirit and truth' (John 4:23-24). The polluted altar is the negative mirror of the living sacrifice Paul calls for (Rom 12:1).</p>",
    "8": "<p>A theme: 'When you offer blind animals in sacrifice, is that not evil? And when you offer those that are lame or sick, is that not evil? Present that to your governor; will he accept you or show you favor?' The standard of what is fit for a king is the standard that applies to worship. The NT standard for the acceptable offering is Christ himself — 'like that of a lamb without blemish or spot' (1 Pet 1:19) — who becomes the pattern for the 'living sacrifice, holy and acceptable to God' (Rom 12:1).</p>",
    "9": "<p>A theme: 'And now entreat the favor of God, that he may be gracious to us. With such a gift from your hand, will he show favor to any of you?' The rhetorical question exposes the futility of seeking grace while offering contempt. The NT answer is Christ as the mediator of true access to God: 'through him we have obtained access by faith into this grace in which we stand' (Rom 5:2). The only adequate basis for entreatment is the intercession of Christ (Heb 7:25).</p>",
    "10": "<p>A direct: 'Oh that there were one among you who would shut the doors, that you might not kindle fire on my altar in vain!' YHWH's rejection of the inadequate temple sacrifice anticipates the once-for-all sacrifice of Christ that renders the Levitical system obsolete: 'there is no longer any offering for sin' (Heb 10:18). The shut temple doors are the opposite of what Heb 10:19-20 announces: 'we have confidence to enter the holy places by the blood of Jesus.'</p>",
    "11": "<p>A direct: 'For from the rising of the sun to its setting my name will be great among the nations, and everywhere incense will be offered to my name.' This verse is among the clearest OT anticipations of universal Gentile worship. The NT fulfillment: the gospel goes to all nations (Matt 28:19); in every place people call on the name of the Lord (1 Cor 1:2); and the final vision is the nations worshipping before the throne (Rev 5:9; 7:9). The 'pure offering' among the nations is the sacrifice of praise through Christ (Heb 13:15).</p>",
    "12": "<p>A theme: 'But you profane it when you say that the Lord's table is polluted.' The contrast between the nations offering pure worship (v11) and Israel's defiled worship (v12) is the paradox Paul addresses in Rom 9-11 — Gentiles attaining righteousness by faith while Israel stumbled (Rom 9:30-31). The holy table that Israel profaned becomes the table Christ sets: 'This is my body given for you; do this in remembrance of me' (Luke 22:19).</p>",
    "13": "<p>A theme: 'But you say, What a weariness this is, and you snort at it.' The contempt for covenantal obligation — worship as a burden rather than a joy — is the disposition Jesus addresses: 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28). The yoke that Israel found heavy Christ makes light (Matt 11:30), transforming obligation into delight through the grace of the gospel.</p>",
    "14": "<p>A direct: 'Cursed be the cheat who has a male in his flock and vows it, and yet sacrifices to the Lord what is blemished.' The curse on inadequate sacrifice sets the standard that only Christ meets. Heb 9:14: Christ 'offered himself without blemish to God.' The law demanded an unblemished offering; Israel consistently fell short; the gospel announces that the unblemished lamb has finally been offered once for all. The curse of v14 is absorbed by the one who 'became a curse for us' (Gal 3:13).</p>"
  },
  "2": {
    "1": "<p>A theme: The charge to the priests — 'this commandment is for you' — makes the spiritual leaders primarily accountable for covenant faithfulness. Jesus applies the same accountability with greater force: 'Let not many of you become teachers, my brothers, for you know that we who teach will be judged with greater strictness' (Jas 3:1). The priest's responsibility to model covenant life is fulfilled perfectly only in Christ, the great high priest who is 'holy, innocent, unstained, separated from sinners' (Heb 7:26).</p>",
    "2": "<p>A theme: 'If you will not listen, if you will not take it to heart to give honor to my name, says YHWH of hosts, then I will send the curse upon you.' The covenantal consequence of dishonoring YHWH's name — blessing reversed to curse — is the framework for the cross. Christ, who is himself the blessing (Gal 3:14), becomes the curse (Gal 3:13) so that the curse declared in texts like this verse might be absorbed and reversed.</p>",
    "3": "<p>A theme: 'Behold, I will rebuke your offspring, and spread dung on your faces.' The degradation of corrupt priests — their dignity reversed to shame — is the negative foil for the dignity Christ restores. The shame of the cross becomes the robe of righteousness; the humiliation of the priesthood becomes the honor of the royal priesthood Christ creates (1 Pet 2:9).</p>",
    "4": "<p>A type: 'So shall you know that I have sent this command to you, that my covenant with Levi may stand.' The Levitical covenant — life and peace given to Levi (v5) in exchange for reverent, faithful service — is the OT type that the new covenant in Christ fulfills and surpasses. Heb 7:11-12: 'if perfection had been attainable through the Levitical priesthood, why would there still have been a need for another priest to arise after the order of Melchizedek?' The Levitical covenant is honored by being replaced with something better.</p>",
    "5": "<p>A type: 'My covenant with him was one of life and peace, and I gave them to him.' Life and peace as the content of the priestly covenant are fulfilled in Christ's mediatorial work. John 10:10: 'I came that they may have life and have it abundantly.' Rom 5:1: 'we have peace with God through our Lord Jesus Christ.' The life-and-peace covenant of Levi points to the new covenant in which Christ is himself the life (John 14:6) and our peace (Eph 2:14).</p>",
    "6": "<p>A direct: 'True instruction was in his mouth, and no wrong was found on his lips. He walked with me in peace and uprightness.' The ideal priest — truthful speech, blameless walk, covenant faithfulness — is realized perfectly only in Christ. John 14:6 ('I am the way, and the truth, and the life'); 1 Pet 2:22 ('he committed no sin, neither was deceit found in his mouth'); Heb 7:26 (the high priest who is 'holy, innocent, unstained'). Malachi's ideal for the human priest becomes the NT's portrait of the divine-human priest.</p>",
    "7": "<p>A direct: 'For the lips of a priest should guard knowledge, and people should seek instruction from his mouth, for he is the messenger of YHWH of hosts.' The priest as teacher and messenger is fulfilled ultimately in Christ, the Word made flesh and the supreme teacher. Matt 23:8-10: 'You have one teacher, the Christ.' Heb 1:2: 'in these last days he has spoken to us by his Son.' The priest's instructional role reaches its climax in the one who teaches 'as one who had authority, and not as their scribes' (Matt 7:29).</p>",
    "8": "<p>A theme: 'But you have turned aside from the way. You have caused many to stumble by your instruction. You have corrupted the covenant of Levi.' The failure of the human priesthood is the theological necessity behind the divine provision of a new priest. The corruption of the Levitical line is the problem; Christ as the indestructible priest (Heb 7:16) is the solution.</p>",
    "9": "<p>A theme: 'And so I make you despised and abased before all the people.' The humiliation of the unfaithful priests is the negative sign that the true priest — honored rather than shamed — is still to come. The cross appears to be the ultimate priestly humiliation; the resurrection reveals it as the ultimate priestly exaltation: 'God has highly exalted him' (Phil 2:9), the humbled one now exalted above all.</p>",
    "10": "<p>A revelation of God: 'Have we not all one Father? Has not one God created us?' The appeal to the one Father-Creator as the basis for covenant faithfulness is the OT ground of the NT's ethics. The universal fatherhood of God (Matt 5:45) finds its fullest expression in the unique Sonship of Christ, who alone can reveal the Father: 'No one knows the Father except the Son' (Matt 11:27). The 'one Father' of v10 is ultimately the Father of the one Son whose brotherhood is extended to all who believe (Heb 2:11).</p>",
    "11": "<p>A theme: 'Judah has been faithless... he has married the daughter of a foreign god.' The covenant-breaking marriage that imports false worship into Israel is the negative image of the faithful covenant marriage Paul describes in Eph 5:25-32 — Christ and the church as the true marriage covenant. The 'daughter of a foreign god' is the anti-type of the 'pure virgin' Paul wants to present to Christ (2 Cor 11:2).</p>",
    "12": "<p>A theme: 'May YHWH cut off from the tents of Jacob any descendant of the man who does this, who brings an offering to YHWH of hosts!' The exclusion from covenant community for covenant-breaking is the negative sign that covenant membership requires faith and faithfulness. The NT makes explicit what Malachi implies: 'not all who are descended from Israel belong to Israel' (Rom 9:6); membership in the covenant community is defined by faith in Christ (Gal 3:29).</p>",
    "13": "<p>A theme: 'And this second thing you do. You cover the Lord's altar with tears, with weeping and groaning.' The tears at the altar are the grief of wives abandoned by faithless husbands. The injustice that provokes tears before God is exactly what Jesus sees and addresses: 'Will not God give justice to his elect who cry to him day and night?' (Luke 18:7). The weeping at the altar becomes the weeping before the Lord that he promises to vindicate.</p>",
    "14": "<p>A theme: 'You were faithless to the wife of your youth, though she is your companion and your wife by covenant.' The marriage covenant as the model for the divine-human covenant is the subtext of Eph 5:25-32 — 'husbands, love your wives as Christ loved the church.' The faithless husband is the anti-type of Christ, who 'loved the church and gave himself up for her' (Eph 5:25). Malachi's covenant-marriage theology is the OT ground for the NT's theology of the church as the bride of Christ.</p>",
    "15": "<p>A type: 'Did he not make them one, with a portion of the Spirit in him? And what was the one God seeking? Godly offspring.' The one-flesh union of marriage — made by God, marked by his Spirit — is quoted in Matt 19:5 (Jesus on divorce) and applied by Paul in Eph 5:31-32: 'This mystery is profound, and I am saying that it refers to Christ and the church.' The oneness YHWH created in marriage is the type of the oneness Christ creates between himself and the church.</p>",
    "16": "<p>A theme: 'For the man who does not love his wife but divorces her covers his garment with violence.' Covenant faithfulness in marriage as the image of YHWH's own faithfulness to Israel — he does not divorce her despite her unfaithfulness (Hos 2:19-20; Jer 3:1). Christ's faithfulness to the church 'in spite of all' (Rom 8:38-39) is the ultimate expression of the covenant loyalty Malachi demands and Israel failed to maintain.</p>",
    "17": "<p>A theme: 'You have wearied YHWH with your words. But you say, How have we wearied him? By saying, Everyone who does evil is good in the sight of YHWH.' The question 'Where is the God of justice?' (v17b) is the theodicy question that drives toward the cross. The cross is where YHWH demonstrates that he is not indifferent to evil — 'God presented Christ as a propitiation... this was to show God's righteousness, because in his divine forbearance he had passed over former sins' (Rom 3:25-26).</p>"
  },
  "3": {
    "2": "<p>A direct: 'But who can endure the day of his coming, and who can stand when he appears? For he is like a refiner's fire and like fullers' soap.' The question that follows the announcement of ch3:1 (fulfilled in John the Baptist and Jesus) is the question of the eschatological encounter with the holy God. Rev 6:17: 'for the great day of their wrath has come, and who can stand?' The answer is: those purified by Christ, who is both the refiner and the one who makes standing possible — 'he is able to make you stand' (Rom 14:4; Jude 24).</p>",
    "3": "<p>A direct: 'He will sit as a refiner and purifier of silver, and he will purify the sons of Levi.' Christ's ongoing purifying work in the church — 'so that he might present the church to himself in splendor, without spot or wrinkle or any such thing' (Eph 5:27) — is the NT fulfillment of the Refiner at work. 1 Pet 1:7: 'the tested genuineness of your faith — more precious than gold that perishes though it is tested by fire — may be found to result in praise and glory and honor at the revelation of Jesus Christ.' The Refiner's purpose is not destruction but purification.</p>",
    "4": "<p>A direct: 'Then the offering of Judah and Jerusalem will be pleasing to YHWH as in the days of old.' The restoration of acceptable worship through the Messiah's purifying work is the NT vision of the acceptable sacrifice. Rom 15:16: Paul serves as a 'minister of Christ Jesus to the Gentiles in the priestly service of the gospel of God, so that the offering of the Gentiles may be acceptable.' Phil 4:18: the Philippians' gift is 'a fragrant offering, a sacrifice acceptable and pleasing to God.' The pleasing offering is restored through Christ.</p>",
    "5": "<p>A theme: 'Then I will draw near to you for judgment. I will be a swift witness against the sorcerers, against the adulterers, against those who swear falsely, against those who oppress the hired worker in his wages, the widow and the fatherless, against those who thrust aside the sojourner.' The divine justice that Malachi demands finds its ultimate expression in the judgment 'of the living and the dead' entrusted to Christ (Acts 10:42; 2 Tim 4:1). The eschatological reckoning Christ inaugurates is the answer to the injustices catalogued here.</p>",
    "6": "<p>A revelation of God: 'For I YHWH do not change; therefore you, O children of Jacob, are not consumed.' The immutability of YHWH is the ground of covenant faithfulness — his constancy is Israel's security. Heb 13:8 applies this divine attribute directly to Christ: 'Jesus Christ is the same yesterday and today and forever.' The unchanging God of Malachi 3:6 is the same unchanging Christ of Hebrews — the one 'who is able to save to the uttermost those who draw near to God through him' (Heb 7:25).</p>",
    "7": "<p>A theme: 'From the days of your fathers you have turned aside from my statutes and have not kept them. Return to me, and I will return to you.' The call to return that opens Zechariah (1:3) is echoed here. This mutual-return pattern is the OT grammar of the parable of the prodigal son — the father running to meet the returning child. Christ is the one who makes the return possible: 'I am the way' (John 14:6); 'No one comes to the Father except through me.'</p>",
    "8": "<p>A theme: 'Will man rob God? Yet you are robbing me. But you say, How have we robbed you? In your tithes and contributions.' The test of generosity — giving back to God what belongs to him — is the OT basis for the NT theology of stewardship. 2 Cor 9:6-8: 'Whoever sows sparingly will also reap sparingly... Each one must give as he has decided in his heart, not reluctantly or under compulsion, for God loves a cheerful giver.' The robbing of God through withheld tithes is the negative example for the abundant generosity Christ calls forth.</p>",
    "9": "<p>A theme: 'You are cursed with a curse, for you are robbing me, the whole nation of you.' The covenant curse invoked by covenant unfaithfulness is the context for Gal 3:10-13: 'all who rely on works of the law are under a curse... Christ redeemed us from the curse of the law by becoming a curse for us.' The curse Malachi invokes is real; Christ's absorption of that curse is the gospel answer.</p>",
    "10": "<p>A theme: 'Bring the full tithe into the storehouse... and thereby put me to the test... if I will not open the windows of heaven for you.' The invitation to test YHWH in the matter of generosity is the OT's boldest statement that covenant obedience produces covenant blessing. 2 Cor 9:8: 'God is able to make all grace abound to you, so that having all sufficiency in all things at all times, you may abound in every good work.' The window opened in response to the tithe is the type of the superabundant grace opened by Christ's sacrifice.</p>",
    "11": "<p>A theme: 'I will rebuke the devourer for you, so that it will not destroy the fruits of your soil.' The divine protection of the covenant community's fruitfulness is the OT type of Christ's protecting promise: 'I give them eternal life, and they will never perish, and no one will snatch them out of my hand' (John 10:28-29). The devourer rebuked in Malachi 3:11 is the enemy Christ defeats: 'the thief comes only to steal and kill and destroy. I came that they may have life and have it abundantly' (John 10:10).</p>",
    "12": "<p>A direct: 'Then all nations will call you blessed, for you will be a land of delight, says YHWH of hosts.' The eschatological beatitude of all nations calling Israel blessed is the Abrahamic promise fulfilled through Christ: 'in you all the families of the earth shall be blessed' (Gen 12:3); 'so that in Christ Jesus the blessing of Abraham might come to the Gentiles' (Gal 3:14). Rev 22:3: 'the throne of God and of the Lamb will be in it, and his servants will worship him.' The blessed nation becomes, in Christ, the blessed multi-national family.</p>",
    "13": "<p>A theme: 'Your words have been harsh against me, says YHWH. But you say, How have we spoken against you?' The unconscious arrogance of the doubters who cannot see their own faithlessness is the condition Christ addresses in the Laodicean church letter: 'For you say, I am rich, I have prospered, and I need nothing, not realizing that you are wretched, pitiable, poor, blind, and naked' (Rev 3:17). Christ's counsel — to buy gold refined by fire — is the answer to the harsh words that project the problem outward.</p>",
    "14": "<p>A theme: 'You have said, It is vain to serve God. What is the profit of our keeping his charge?' The utilitarian calculation of covenant faithfulness — 'what's in it for us?' — is the crisis of faith that the prosperity of the wicked (v15) exacerbates. The psalmist's crisis in Ps 73 ('was it for nothing I kept my heart pure?') finds its resolution in 'the sanctuary of God' (Ps 73:17) — the place of Christ's presence. The apparent futility of service is resolved in the resurrection: 'Therefore, my beloved brothers, be steadfast, immovable, always abounding in the work of the Lord, knowing that in the Lord your labor is not in vain' (1 Cor 15:58).</p>",
    "15": "<p>A theme: 'And now we call the arrogant blessed. Evildoers not only prosper but they put God to the test and they escape.' The theodicy crisis — the wicked prosper, the righteous suffer — is the question that the cross definitively addresses. The cross shows that God does not ignore injustice; the resurrection shows that suffering for righteousness is not the end. Rom 8:18: 'the sufferings of this present time are not worth comparing with the glory that is to be revealed to us.'</p>",
    "16": "<p>A type: 'Then those who feared YHWH spoke with one another. YHWH paid attention and heard them, and a book of remembrance was written before him of those who feared YHWH and esteemed his name.' The book of remembrance of the faithful is the OT type of the 'book of life' in Revelation (Rev 3:5; 20:12,15; 21:27). The community of the God-fearers who gather in crisis is the type of the NT church gathered around the Word. Christ is the one who writes names in the book of life (Rev 3:5) and before whom the books are opened (Rev 20:12).</p>",
    "17": "<p>A direct: 'They shall be mine, says YHWH of hosts, in the day when I make up my treasured possession (<em>segullah</em>), and I will spare them as a man spares his son who serves him.' <em>Segullah</em> (treasured possession, special property) is covenant language from Exod 19:5 ('you shall be my treasured possession'). 1 Pet 2:9 applies it to the church: 'a people for his own possession' (<em>laos eis peripoiesin</em>). The 'day when I act' is Christ's parousia — the day when the gathered treasure of the faithful is revealed.</p>",
    "18": "<p>A direct: 'Then once more you shall see the distinction between the righteous and the wicked, between one who serves God and one who does not serve him.' The final discrimination between the righteous and wicked is fulfilled in Christ's eschatological judgment. Matt 25:31-46: the Son of Man separates the sheep from the goats. John 5:28-29: 'an hour is coming when all who are in the tombs will hear his voice and come out, those who have done good to the resurrection of life, and those who have done evil to the resurrection of judgment.' The distinction Malachi announces, Christ enacts.</p>"
  },
  "4": {
    "1": "<p>A direct: 'For behold, the day is coming, burning like an oven, when all the arrogant and all evildoers will be stubble. The day that is coming shall set them ablaze.' The eschatological day of fire that consumes the wicked is a key NT theme: 2 Thess 1:7-8 ('in flaming fire, inflicting vengeance on those who do not know God and on those who do not obey the gospel of our Lord Jesus'); Rev 20:15 ('anyone whose name was not found written in the book of life was thrown into the lake of fire'). The burning day anticipated in Malachi 4:1 arrives in Christ's parousia judgment.</p>",
    "2": "<p>A direct: 'But for you who fear my name, the sun of righteousness shall rise with healing in its wings.' This is among the most explicitly Messianic verses in the Minor Prophets. The Fathers consistently identified the 'sun of righteousness' with Christ. Luke 1:78-79: Zechariah's Benedictus calls Christ 'the sunrise from on high' (<em>anatole ex hupsous</em>) who visits 'to give light to those who sit in darkness.' John 1:4-5: 'in him was life, and the life was the light of men.' Rev 22:16: 'I, Jesus, am the root and the descendant of David, the bright morning star.' The healing in the wings is the atonement's restorative power.</p>",
    "3": "<p>A theme: 'And you shall go out leaping like calves from the stall. And you shall tread down the wicked, for they will be ashes under the soles of your feet.' The triumphant joy of the redeemed trampling on what had oppressed them is the NT's eschatological victory. Rev 2:26-27: 'The one who conquers... I will give him authority over the nations.' 1 Cor 15:25: 'he must reign until he has put all his enemies under his feet.' The leaping calves celebrate a freedom won by Christ who has 'disarmed the rulers and authorities' (Col 2:15).</p>",
    "4": "<p>A theme: 'Remember the law of Moses my servant, which I commanded him at Horeb for all Israel, with the statutes and rules.' The Torah as the standing instruction is the preparation for Christ, 'our schoolmaster to bring us to Christ' (Gal 3:24 KJV). Jesus's own summary: 'Do not think I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17). The remembrance of Moses's law is the OT's final word before the forerunner and the one greater than Moses arrive.</p>",
    "6": "<p>A direct: 'And he will turn the hearts of fathers to their children and the hearts of children to their fathers, lest I come and strike the land with a decree of utter destruction.' The final verse of the OT turns on the relational restoration that the forerunner's ministry accomplishes. Luke 1:17: John the Baptist will go before the Lord 'to turn the hearts of the fathers to the children, and the disobedient to the wisdom of the just, to make ready for the Lord a people prepared.' The family reconciliation Malachi envisions is the social fruit of the gospel — the Spirit poured out turning hearts toward one another across generations (Acts 2:17).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'malachi')
    merge_comm(existing, MALACHI)
    save_comm('mkt-christ', 'malachi', existing)
    print('Malachi 1-4 christ written.')

if __name__ == '__main__':
    main()
